        $matrix['max-parallel'] | Should -Be 4
    }

    It 'passes through fail-fast = false' {
        $matrix = New-BuildMatrix -Config @{ os = @('a'); 'fail-fast' = $false }
        $matrix['fail-fast'] | Should -Be $false
    }

